import scala.util.matching.Regex

def solve(code: Array[String], businessLine: Array[String], isActive: Array[Boolean]): Array[String] = {
  val validBusinessLines = Set("electronics", "grocery", "pharmacy", "restaurant")
  val businessLineOrder = Map("electronics" -> 0, "grocery" -> 1, "pharmacy" -> 2, "restaurant" -> 3)
  val pattern: Regex = "^[a-zA-Z0-9_]+$".r

  val validCoupons = (code, businessLine, isActive).zipped.toArray.collect {
    case (c, bl, active) if 
      c.nonEmpty && 
      pattern.matches(c) && 
      validBusinessLines.contains(bl) && 
      active => (c, bl)
  }

  validCoupons.sortBy { case (c, bl) => (businessLineOrder(bl), c) }
    .map { case (c, _) => c }
}
